// Parse CalDAV XML response
const xml = $input.first().json.data || '';
const tasks = [];
const vtodoMatches = xml.match(/<cal:VTODO[^>]*>[\s\S]*?<\/cal:VTODO>/gi) || [];

for (const vtodo of vtodoMatches) {
  const extract = (tag) => {
    const match = vtodo.match(new RegExp(`<cal:${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'));
    return match ? match[1] : null;
  };

  tasks.push({
    uid: extract('UID') || 'unknown',
    title: extract('SUMMARY') || 'Untitled',
    description: extract('DESCRIPTION'),
    status: extract('STATUS') || 'NEEDS-ACTION',
    due: extract('DTEND'),
    startDate: extract('DTSTART'),
    completed: extract('COMPLETED'),
    priority: extract('PRIORITY') ? parseInt(extract('PRIORITY')) : null,
    percentComplete: extract('PERCENT-COMPLETE') ? parseInt(extract('PERCENT-COMPLETE')) : null,
    categories: extract('CATEGORIES') ? extract('CATEGORIES').split(',').map(c => c.trim()) : [],
    duration: extract('DURATION'),
    recurrence: extract('RRULE'),
    location: extract('LOCATION'),
    url: extract('URL'),
    href: vtodo.match(/<d:href>([^<]*)<\/d:href>/i)?.[1] || null
  });
}

return [{ json: { success: true, tasks, count: tasks.length } }];

// Build ICS for create
const body = $('Set Config').first().json.nextcloudUrl ? $('Set Config').first().json.webhookBody : $('Set Config').first().json.webhookBody;
const taskId = Date.now();

const formatICalDate = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  const hours = String(d.getUTCHours()).padStart(2, '0');
  const minutes = String(d.getUTCMinutes()).padStart(2, '0');
  const seconds = String(d.getUTCSeconds()).padStart(2, '0');
  return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
};

const parseDate = (dateStr) => {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return isNaN(d.getTime()) ? null : d;
};

const now = new Date();
const lines = [
  'BEGIN:VCALENDAR',
  'VERSION:2.0',
  'PRODID:-//n8n//Nextcloud//EN',
  'BEGIN:VTODO',
  `UID:n8n-task-${taskId}`,
  `DTSTAMP:${formatICalDate(now)}`
];

if (body.title) lines.push(`SUMMARY:${body.title}`);
if (body.description) lines.push(`DESCRIPTION:${body.description}`);
if (body.due) { const d = parseDate(body.due); if (d) lines.push(`DUE:${formatICalDate(d)}`); }
if (body.startDate) { const d = parseDate(body.startDate); if (d) lines.push(`DTSTART:${formatICalDate(d)}`); }
if (body.completed) { const d = parseDate(body.completed); if (d) lines.push(`COMPLETED:${formatICalDate(d)}`); }

if (body.status) {
  const statusMap = { 'todo': 'NEEDS-ACTION', 'in-progress': 'IN-PROCESS', 'completed': 'COMPLETED', 'cancelled': 'CANCELLED' };
  lines.push(`STATUS:${statusMap[body.status] || body.status}`);
} else {
  lines.push('STATUS:NEEDS-ACTION');
}

if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9, Math.max(1, parseInt(body.priority)))}`);
if (body.percentComplete !== undefined) lines.push(`PERCENT-COMPLETE:${Math.min(100, Math.max(0, parseInt(body.percentComplete)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories) ? body.categories.join(',') : body.categories}`);
if (body.parentTaskUid) lines.push(`RELATED-TO;RELTYPE=PARENT:${body.parentTaskUid}`);
if (body.duration) lines.push(`DURATION:${body.duration}`);
if (body.recurrence) lines.push(`RRULE:${body.recurrence}`);
if (body.location) lines.push(`LOCATION:${body.location}`);
if (body.url) lines.push(`URL:${body.url}`);

lines.push('END:VTODO', 'END:VCALENDAR');

return [{ json: { icsBody: lines.join('\r\n'), nextcloudUrl: $('Set Config').first().json.nextcloudUrl, nextcloudUser: $('Set Config').first().json.nextcloudUser } }];

// Build ICS for update
const body = $('Set Config').first().json.webhookBody;
if (!body.taskUid) return [{ json: { success: false, message: 'taskUid is required' } }];

const formatICalDate = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  const hours = String(d.getUTCHours()).padStart(2, '0');
  const minutes = String(d.getUTCMinutes()).padStart(2, '0');
  const seconds = String(d.getUTCSeconds()).padStart(2, '0');
  return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
};

const now = new Date();
const lines = [
  'BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//n8n//Nextcloud//EN',
  'BEGIN:VTODO', `UID:${body.taskUid}`, `DTSTAMP:${formatICalDate(now)}`
];

if (body.title !== undefined) lines.push(`SUMMARY:${body.title}`);
if (body.description !== undefined) lines.push(`DESCRIPTION:${body.description}`);
if (body.due) { const d = new Date(body.due); if (!isNaN(d.getTime())) lines.push(`DUE:${formatICalDate(d)}`); }

if (body.status) {
  const statusMap = { 'todo': 'NEEDS-ACTION', 'in-progress': 'IN-PROCESS', 'completed': 'COMPLETED', 'cancelled': 'CANCELLED' };
  lines.push(`STATUS:${statusMap[body.status] || body.status}`);
  if (body.status === 'completed' || body.status === 'COMPLETED') lines.push(`COMPLETED:${formatICalDate(now)}`);
}

if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9, Math.max(1, parseInt(body.priority)))}`);
if (body.percentComplete !== undefined) lines.push(`PERCENT-COMPLETE:${Math.min(100, Math.max(0, parseInt(body.percentComplete)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories) ? body.categories.join(',') : body.categories}`);

lines.push('END:VTODO', 'END:VCALENDAR');

const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;

return [{ json: { icsBody: lines.join('\r\n'), taskUrl: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/tasks/${body.taskUid}.ics`, taskUid: body.taskUid } }];

const body = $('Set Config').first().json.webhookBody;
if (!body.taskUid) return [{ json: { success: false, message: 'taskUid is required' } }];

const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;

return [{ json: { taskUrl: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/tasks/${body.taskUid}.ics`, taskUid: body.taskUid } }];
